69	pub(crate) struct Sources {
70	    routers: Vec<ZenohIdProto>,
71	    peers: Vec<ZenohIdProto>,
72	    clients: Vec<ZenohIdProto>,
73	}
74	
75	impl Sources {
76	    pub(crate) fn empty() -> Self {
77	        Self {
78	            routers: vec![],
79	            peers: vec![],
80	            clients: vec![],
81	        }
82	    }
83	
84	    pub(crate) fn is_empty(&self) -> bool {
85	        self.routers.is_empty() && self.peers.is_empty() && self.clients.is_empty()
86	    }
87	
88	    pub(crate) fn with_mode(
89	        mut self,
90	        zids: impl IntoIterator<Item = ZenohIdProto>,
91	        mode: WhatAmI,
92	    ) -> Self {
93	        match mode {
94	            WhatAmI::Router => self.routers.extend(zids),
95	            WhatAmI::Peer => self.peers.extend(zids),
96	            WhatAmI::Client => self.clients.extend(zids),
97	        }
98	        self
99	    }
100	
101	    pub(crate) fn extend(&mut self, other: &Sources) {
102	        self.routers.extend(other.routers.iter().copied());
103	        self.peers.extend(other.peers.iter().copied());
104	        self.clients.extend(other.clients.iter().copied());
105	    }
106	}
