261	    /// Returns `true` if `face` belongs to this [`Hat`].
262	    fn owns(&self, face: &FaceState) -> bool {
263	        if self.region() == face.region && face.remote_bound.is_north() {
264	            debug_assert_eq!(self.mode(), face.whatami);
265	            debug_assert_eq!(face.is_local, self.region() == Region::Local);
266	            debug_assert_implies!(face.is_local, face.whatami.is_client());
267	        }
268	
269	        self.region() == face.region
270	    }
