272	    /// Disables this hat's data routes for the given resource and all its matches.
273	    fn disable_data_routes(&mut self, res: &mut Arc<Resource>) {
274	        if res.ctx.is_some() {
275	            get_mut_unchecked(res).context_mut().hats[self.region()].disable_data_routes();
276	            get_mut_unchecked(res).context_mut().disable_data_routes();
277	
278	            for match_ in &res.context().matches {
279	                let mut match_ = match_.upgrade().unwrap();
280	                if !Arc::ptr_eq(&match_, res) {
281	                    get_mut_unchecked(&mut match_).context_mut().hats[self.region()]
282	                        .disable_data_routes();
283	                    get_mut_unchecked(&mut match_)
284	                        .context_mut()
285	                        .disable_data_routes();
286	                }
287	            }
288	        }
289	    }
290	
291	    /// Disables this hat's query routes for the given resource and all its matches.
292	    fn disable_query_routes(&mut self, res: &mut Arc<Resource>) {
293	        if res.ctx.is_some() {
294	            get_mut_unchecked(res).context_mut().hats[self.region()].disable_query_routes();
295	
296	            for match_ in &res.context().matches {
297	                let mut match_ = match_.upgrade().unwrap();
298	                if !Arc::ptr_eq(&match_, res) {
299	                    get_mut_unchecked(&mut match_).context_mut().hats[self.region()]
300	                        .disable_query_routes();
301	                }
302	            }
303	        }
304	    }
305	
306	    /// Disables this hat's data and query routes **for all resources**.
307	    fn disable_all_routes(&mut self, tables: &mut TablesData) {
308	        let routes_version = &mut tables.hats[self.region()].routes_version;
309	        *routes_version = routes_version.saturating_add(1);
310	
311	        tables.disable_all_routes();
312	    }
313	}
