337	/// Hat interest protocol interface.
338	///
339	/// Below is the typical code-path for each message type.
340	///
341	/// # Interest w/ `mode=Current` or `mode=CurrentFuture`
342	///   1. [`HatInterestTrait::route_interest`] on the north hat.
343	///   2. [`HatInterestTrait::register_interest`] on the owner south hat, iff it owns the src face.
344	///   3. [`HatInterestTrait::send_current_tokens`] on the owner south hat, iff it owns the src face.
345	///   4. [`HatInterestTrait::send_current_queryables`] on the owner south hat, iff it owns the src face.
346	///   4. [`HatInterestTrait::send_current_tokens`] on the owner south hat, iff it owns the src face.
347	///   5. [`HatInterestTrait::send_declare_final`] on the owner south hat,
348	///      iff it owns the src face and there is no gateway in the north region.
349	///
350	/// # `Interest` w/ `mode=Final`
351	///   1. [`HatInterestTrait::route_interest_final`] on the north hat.
352	///   2. [`HatInterestTrait::unregister_interest`] on the owner south hat, iff it owns the src face.
353	///
354	/// # `DeclareFinal` (final)
355	///   1. [`HatInterestTrait::route_declare_final`] on the north hat.
356	///   2. [`HatInterestTrait::send_declare_final`] on the owner south hat, iff the msg is intended for it.
357	///
358	/// # `DeclareToken` (w/ interest id)
359	///   1. [`HatInterestTrait::route_current_token`] on the north hat.
360	///   2. [`HatInterestTrait::propagate_current_token`] on the owner south hat, iff the msg is intended for it.
361	pub(crate) trait HatInterestTrait {
362	    fn route_interest(
363	        &mut self,
364	        ctx: DispatcherContext,
365	        msg: &Interest,
366	        res: Option<Arc<Resource>>,
367	        src: &Remote,
368	    ) -> RouteInterestResult;
369	
370	    fn route_interest_final(
371	        &mut self,
372	        ctx: DispatcherContext,
373	        msg: &Interest,
374	        remote_interest: &RemoteInterest,
375	    );
376	
377	    fn route_declare_final(
378	        &mut self,
379	        ctx: DispatcherContext,
380	        interest_id: InterestId,
381	    ) -> RouteCurrentDeclareResult;
382	
383	    fn route_current_token(
384	        &mut self,
385	        ctx: DispatcherContext,
386	        interest_id: InterestId,
387	        res: Arc<Resource>,
388	    ) -> RouteCurrentDeclareResult;
389	
390	    fn send_current_subscribers(
391	        &self,
392	        ctx: DispatcherContext,
393	        msg: &Interest,
394	        res: Option<Arc<Resource>>,
395	        other_matches: HashMap<Arc<Resource>, SubscriberInfo>,
396	    );
397	
398	    fn send_current_queryables(
399	        &self,
400	        ctx: DispatcherContext,
401	        msg: &Interest,
402	        res: Option<Arc<Resource>>,
403	        other_matches: HashMap<Arc<Resource>, QueryableInfoType>,
404	    );
405	
406	    fn send_current_tokens(
407	        &self,
408	        ctx: DispatcherContext,
409	        msg: &Interest,
410	        res: Option<Arc<Resource>>,
411	        other_matches: HashSet<Arc<Resource>>,
412	    );
413	
414	    fn propagate_current_token(
415	        &self,
416	        ctx: DispatcherContext,
417	        res: Arc<Resource>,
418	        interest: CurrentInterest,
419	    );
420	
421	    fn send_declare_final(&mut self, ctx: DispatcherContext, interest_id: InterestId, dst: &Remote);
422	
423	    fn register_interest(
424	        &mut self,
425	        ctx: DispatcherContext,
426	        msg: &Interest,
427	        res: Option<Arc<Resource>>,
428	    );
429	
430	    fn unregister_interest(
431	        &mut self,
432	        ctx: DispatcherContext,
433	        msg: &Interest,
434	    ) -> Option<RemoteInterest>;
435	
436	    fn remote_interests(&self, tables: &TablesData) -> HashSet<RemoteInterest>;
437	}
