74	impl TreesComputationWorker {
75	    fn new(region: Region) -> Self {
76	        let (tx, rx) = flume::bounded::<Arc<TablesLock>>(1);
77	        let task = TerminatableTask::spawn_abortable(zenoh_runtime::ZRuntime::Net, async move {
78	            loop {
79	                tokio::time::sleep(std::time::Duration::from_millis(
80	                    *TREES_COMPUTATION_DELAY_MS,
81	                ))
82	                .await;
83	
84	                if let Ok(tables_ref) = rx.recv_async().await {
85	                    let mut wtables = zwrite!(tables_ref.tables);
86	                    let tables = &mut *wtables;
87	
88	                    tables.hats[region]
89	                        .as_any_mut()
90	                        .downcast_mut::<Hat>()
91	                        .unwrap()
92	                        .do_compute_trees(&mut tables.data);
93	                }
94	            }
95	        });
96	        Self { _task: task, tx }
97	    }
98	}
