237	impl HatBaseTrait for Hat {
238	    fn init(&mut self, tables: &mut TablesData, runtime: Runtime) -> ZResult<()> {
239	        let config_guard = runtime.config().lock();
240	        let config = &config_guard;
241	        let whatami = config.mode();
242	        let gossip = unwrap_or_default!(config.scouting().gossip().enabled());
243	        let gossip_multihop = unwrap_or_default!(config.scouting().gossip().multihop());
244	        let gossip_target = *unwrap_or_default!(config.scouting().gossip().target().get(whatami));
245	        if gossip_target.matches(WhatAmI::Client) {
246	            bail!("\"client\" is not allowed as gossip target")
247	        }
248	        let autoconnect = if gossip {
249	            AutoConnect::gossip(config, whatami, runtime.zid().into())
250	        } else {
251	            AutoConnect::disabled()
252	        };
253	
254	        let router_link_weights = config
255	            .routing()
256	            .router()
257	            .linkstate()
258	            .transport_weights()
259	            .clone();
260	        drop(config_guard);
261	
262	        self.routers_net = Some(Network::new(
263	            ROUTERS_NET_NAME.to_string(),
264	            tables.zid,
265	            runtime.clone(),
266	            true,
267	            gossip,
268	            gossip_multihop,
269	            gossip_target,
270	            autoconnect,
271	            link_weights_from_config(router_link_weights, ROUTERS_NET_NAME)?,
272	            self.region().bound(),
273	        ));
274	        Ok(())
275	    }
