320	    #[tracing::instrument(level = "debug", skip(ctx, other_hats), ret)]
321	    fn handle_oam(
322	        &mut self,
323	        mut ctx: DispatcherContext,
324	        oam: &mut Oam,
325	        other_hats: RegionMap<&mut dyn HatTrait>,
326	    ) -> ZResult<()> {
327	        if oam.id == OAM_LINKSTATE {
328	            debug_assert_implies!(
329	                !ctx.src_face.whatami.is_router(),
330	                ctx.src_face.remote_bound.is_south()
331	            );
332	
333	            if let ZExtBody::ZBuf(buf) = mem::take(&mut oam.body) {
334	                use zenoh_buffers::reader::HasReader;
335	                use zenoh_codec::RCodec;
336	                let codec = Zenoh080Routing::new();
337	                let mut reader = buf.reader();
338	                let Ok(list): Result<LinkStateList, _> = codec.read(&mut reader) else {
339	                    bail!("failed to decode link state");
340	                };
341	
342	                tracing::trace!(linkstate = ?list);
343	
344	                let removed_nodes = self
345	                    .net_mut()
346	                    .link_states(list.link_states, ctx.src_face.zid)
347	                    .removed_nodes;
348	
349	                let removed_subscribers = removed_nodes
350	                    .iter()
351	                    .flat_map(|(_, node)| self.unregister_node_subscribers(node))
352	                    .collect::<HashSet<_>>();
353	
354	                let removed_queryables = removed_nodes
355	                    .iter()
356	                    .flat_map(|(_, node)| self.unregister_node_queryables(node))
357	                    .collect::<HashSet<_>>();
358	
359	                let removed_tokens = removed_nodes
360	                    .iter()
361	                    .flat_map(|(_, node)| self.unregister_node_tokens(node))
362	                    .collect::<HashSet<_>>();
363	
364	                let region = self.region();
365	
366	                let mut hats = other_hats
367	                    .into_iter()
368	                    .chain(iter::once((self.region, self as &mut dyn HatTrait)))
369	                    .collect::<RegionMap<_>>();
370	
371	                for mut res in removed_subscribers {
372	                    hats[region].disable_data_routes(&mut res);
373	
374	                    let mut remaining = hats
375	                        .values_mut()
376	                        .filter(|hat| hat.remote_subscribers_of(ctx.tables, &res).is_some())
377	                        .collect_vec();
378	
379	                    if remaining.is_empty() {
380	                        for hat in hats.values_mut() {
381	                            hat.unpropagate_subscriber(ctx.reborrow(), res.clone());
382	                        }
383	                        Resource::clean(&mut res);
384	                    } else if let [last_owner] = &mut *remaining {
385	                        last_owner
386	                            .unpropagate_last_non_owned_subscriber(ctx.reborrow(), res.clone())
387	                    }
388	                }
389	
390	                for mut res in removed_queryables {
391	                    hats[region].disable_query_routes(&mut res);
392	
393	                    let remaining = hats
394	                        .iter()
395	                        .filter_map(|(rgn, hat)| {
396	                            hat.remote_queryables_of(ctx.tables, &res)
397	                                .map(|info| (rgn, info))
398	                        })
399	                        .collect_vec();
400	
401	                    match &*remaining {
402	                        [] => {
403	                            for hat in hats.values_mut() {
404	                                hat.unpropagate_queryable(ctx.reborrow(), res.clone());
405	                            }
406	                            Resource::clean(&mut res);
407	                        }
408	                        [(last_owner, _)] => hats[last_owner]
409	                            .unpropagate_last_non_owned_queryable(ctx.reborrow(), res.clone()),
410	                        _ => {
411	                            for hat in hats.values_mut() {
412	                                let other_info = remaining
413	                                    .iter()
414	                                    .filter_map(|(region, info)| {
415	                                        (region != &hat.region()).then_some(*info)
416	                                    })
417	                                    .reduce(merge_qabl_infos);
418	
419	                                hat.propagate_queryable(ctx.reborrow(), res.clone(), other_info);
420	                            }
421	                        }
422	                    }
423	                }
424	
425	                for mut res in removed_tokens {
426	                    let mut remaining = hats
427	                        .values_mut()
428	                        .filter(|hat| hat.remote_tokens_of(ctx.tables, &res))
429	                        .collect_vec();
430	
431	                    if remaining.is_empty() {
432	                        for hat in hats.values_mut() {
433	                            hat.unpropagate_token(ctx.reborrow(), res.clone());
434	                        }
435	                        Resource::clean(&mut res);
436	                    } else if let [last_owner] = &mut *remaining {
437	                        last_owner.unpropagate_last_non_owned_token(ctx.reborrow(), res.clone())
438	                    }
439	                }
440	
441	                hats[region]
442	                    .as_any_mut()
443	                    .downcast_mut::<Self>()
444	                    .unwrap()
445	                    .compute_trees(ctx);
446	            }
447	        }
448	
449	        Ok(())
450	    }
