281	    #[tracing::instrument(level = "debug", skip(ctx, transport, other_hats), fields(src = %ctx.src_face), ret)]
282	    fn new_transport_unicast_face(
283	        &mut self,
284	        mut ctx: DispatcherContext,
285	        transport: &TransportUnicast,
286	        other_hats: RegionMap<&dyn HatTrait>,
287	    ) -> ZResult<()> {
288	        debug_assert!(self.owns(ctx.src_face));
289	
290	        if let Some(net) = self.net_mut() {
291	            net.add_link(transport.clone(), ctx.src_face.remote_bound);
292	        }
293	
294	        // NOTE(regions): we only send/recv initial interests between peers that are mutually north-bound,
295	        // otherwise we are in PULL mode. In particular, the `open.return_conditions.declares` configuration
296	        // option doesn't apply to region gateways.
297	        let do_initial_interest =
298	            ctx.src_face.region.bound().is_north() && ctx.src_face.remote_bound.is_north();
299	
300	        tracing::debug!(do_initial_interest);
301	
302	        if do_initial_interest {
303	            let face_id = ctx.src_face.id;
304	            get_mut_unchecked(ctx.src_face).local_interests.insert(
305	                INITIAL_INTEREST_ID,
306	                InterestState::new(face_id, InterestOptions::ALL, None, false),
307	            );
308	        }
309	
310	        self.repropagate_interests(ctx.reborrow(), &other_hats);
311	        self.repropagate_subscribers(ctx.reborrow(), &other_hats);
312	        self.repropagate_queryables(ctx.reborrow(), &other_hats);
313	        self.repropagate_tokens(ctx.reborrow(), &other_hats);
314	        self.disable_all_routes(ctx.tables);
315	
316	        if do_initial_interest {
317	            tracing::debug!(dst = %ctx.src_face);
318	            (ctx.send_declare)(
319	                &ctx.src_face.primitives,
320	                RoutingContext::new(Declare {
321	                    interest_id: Some(INITIAL_INTEREST_ID),
322	                    ext_qos: declare::ext::QoSType::DECLARE,
323	                    ext_tstamp: None,
324	                    ext_nodeid: declare::ext::NodeIdType::default(),
325	                    body: DeclareBody::DeclareFinal(DeclareFinal),
326	                }),
327	            );
328	        }
329	
330	        Ok(())
331	    }
