333	    fn close_face(&mut self, ctx: DispatcherContext) {
334	        debug_assert!(self.owns(ctx.src_face));
335	
336	        let mut face_clone = ctx.src_face.clone();
337	        let face = get_mut_unchecked(&mut face_clone);
338	        let hat_face = match face.hats[self.region()].downcast_mut::<HatFace>() {
339	            Some(hate_face) => hate_face,
340	            None => {
341	                tracing::error!("Error downcasting face hat in close_face!");
342	                return;
343	            }
344	        };
345	
346	        hat_face.remote_interests.clear();
347	        hat_face.local_subs.clear();
348	        hat_face.local_qabls.clear();
349	        hat_face.local_tokens.clear();
350	
351	        if let Some(net) = self.net_mut() {
352	            net.remove_link(&face.zid);
353	        }
354	    }
