376	                        bail!("failed to decode link state");
377	                    };
378	
379	                    tracing::trace!(linkstate = ?list);
380	
381	                    net.link_states(list.link_states, ctx.src_face.zid, ctx.src_face.whatami);
382	                }
383	            }
384	        }
