433	    fn gateways_of(&self, _tables: &TablesData, zid: &ZenohIdProto) -> Option<Vec<ZenohIdProto>> {
434	        debug_assert!(self.region().bound().is_south());
435	
436	        let Self::Network {
437	            network: Some(net), ..
438	        } = self
439	        else {
440	            bug!("Invalid peer hat");
