47	
48	impl Hat {
49	    pub(super) fn pubsub_tree_change(
50	        &self,
51	        tables: &mut TablesData,
52	        new_children: &[Vec<NodeIndex>],
53	    ) {
54	        let net = self.net();
55	        // propagate subs to new children
56	        for (tree_sid, tree_children) in new_children.iter().enumerate() {
57	            if !tree_children.is_empty() {
58	                let tree_idx = NodeIndex::new(tree_sid);
59	                if net.graph.contains_node(tree_idx) {
60	                    let tree_id = net.graph[tree_idx].zid;
61	
62	                    let subs_res = &self.router_subs;
63	
64	                    for res in subs_res {
65	                        let subs = &self.res_hat(res).router_subs;
66	                        for sub in subs {
67	                            if *sub == tree_id {
68	                                let sub_info = SubscriberInfo;
69	                                self.send_sourced_subscriber_to_net_children(
70	                                    tables,
71	                                    tree_children,
72	                                    res,
73	                                    None,
74	                                    &sub_info,
75	                                    tree_sid as NodeId,
76	                                );
77	                            }
78	                        }
79	                    }
80	                }
81	            }
82	        }
83	    }
84	
85	    fn send_sourced_subscriber_to_net_children(
86	        &self,
87	        tables: &TablesData,
88	        children: &[NodeIndex],
89	        res: &Arc<Resource>,
90	        src_face: Option<&Arc<FaceState>>,
91	        _sub_info: &SubscriberInfo,
92	        node_id: NodeId,
93	    ) {
94	        let net = self.net();
95	        for child in children {
96	            if net.graph.contains_node(*child) {
97	                match self.face(tables, &net.graph[*child].zid).cloned() {
98	                    Some(mut someface) => {
99	                        if src_face
100	                            .map(|src_face| someface.id != src_face.id)
101	                            .unwrap_or(true)
102	                        {
103	                            let key_expr = Resource::decl_key(res, &mut someface);
104	
105	                            tracing::debug!(dst = %someface);
106	                            someface.primitives.send_declare(RoutingContext::with_expr(
107	                                &mut Declare {
108	                                    interest_id: None,
109	                                    ext_qos: ext::QoSType::DECLARE,
110	                                    ext_tstamp: None,
111	                                    ext_nodeid: ext::NodeIdType { node_id },
112	                                    body: DeclareBody::DeclareSubscriber(DeclareSubscriber {
113	                                        id: SubscriberId::default(), // Sourced subscribers do not use ids
114	                                        wire_expr: key_expr,
115	                                    }),
116	                                },
117	                                res.expr().to_string(),
118	                            ));
119	                        }
120	                    }
121	                    None => {
122	                        tracing::trace!("Unable to find face for zid {}", net.graph[*child].zid)
123	                    }
124	                }
125	            }
126	        }
127	    }
128	
129	    fn propagate_sourced_subscriber(
130	        &self,
131	        tables: &TablesData,
132	        res: &Arc<Resource>,
133	        sub_info: &SubscriberInfo,
134	        src_face: Option<&Arc<FaceState>>,
135	        source: &ZenohIdProto,
136	    ) {
137	        let net = self.net();
138	        match net.get_idx(source) {
139	            Some(tree_sid) => {
140	                if net.trees.len() > tree_sid.index() {
141	                    self.send_sourced_subscriber_to_net_children(
142	                        tables,
143	                        &net.trees[tree_sid.index()].children,
144	                        res,
145	                        src_face,
146	                        sub_info,
147	                        tree_sid.index() as NodeId,
148	                    );
149	                } else {
150	                    tracing::trace!(
151	                        "Propagating sub {}: tree for node {} sid:{} not yet ready",
152	                        res.expr(),
153	                        tree_sid.index(),
154	                        source
155	                    );
156	                }
157	            }
158	            None => tracing::error!(
159	                "Error propagating sub {}: cannot get index of {}!",
160	                res.expr(),
161	                source
162	            ),
163	        }
164	    }
165	
166	    #[inline]
167	    fn send_forget_sourced_subscriber_to_net_children(
168	        &self,
169	        tables: &TablesData,
170	        net: &Network,
171	        children: &[NodeIndex],
172	        res: &Arc<Resource>,
173	        src_face: Option<&Arc<FaceState>>,
174	        routing_context: Option<NodeId>,
175	    ) {
176	        for child in children {
177	            if net.graph.contains_node(*child) {
178	                match self.face(tables, &net.graph[*child].zid).cloned() {
179	                    Some(mut someface) => {
180	                        if src_face
181	                            .map(|src_face| someface.id != src_face.id)
182	                            .unwrap_or(true)
183	                        {
184	                            let wire_expr = Resource::decl_key(res, &mut someface);
185	
186	                            tracing::debug!(dst = %someface);
187	                            someface.primitives.send_declare(RoutingContext::with_expr(
188	                                &mut Declare {
189	                                    interest_id: None,
190	                                    ext_qos: ext::QoSType::DECLARE,
191	                                    ext_tstamp: None,
192	                                    ext_nodeid: ext::NodeIdType {
193	                                        node_id: routing_context.unwrap_or(0),
194	                                    },
195	                                    body: DeclareBody::UndeclareSubscriber(UndeclareSubscriber {
196	                                        id: SubscriberId::default(), // Sourced subscribers do not use ids
197	                                        ext_wire_expr: WireExprType { wire_expr },
198	                                    }),
199	                                },
200	                                res.expr().to_string(),
201	                            ));
202	                        }
203	                    }
204	                    None => {
205	                        tracing::trace!("Unable to find face for zid {}", net.graph[*child].zid)
206	                    }
207	                }
208	            }
209	        }
210	    }
211	
212	    fn propagate_forget_sourced_subscriber(
213	        &self,
214	        tables: &TablesData,
215	        res: &Arc<Resource>,
216	        src_face: Option<&Arc<FaceState>>,
217	        source: &ZenohIdProto,
218	    ) {
219	        let net = self.routers_net.as_ref().unwrap();
220	        match net.get_idx(source) {
221	            Some(tree_sid) => {
222	                if net.trees.len() > tree_sid.index() {
223	                    self.send_forget_sourced_subscriber_to_net_children(
224	                        tables,
225	                        net,
226	                        &net.trees[tree_sid.index()].children,
227	                        res,
228	                        src_face,
229	                        Some(tree_sid.index() as NodeId),
230	                    );
231	                } else {
232	                    tracing::trace!(
233	                        "Propagating forget sub {}: tree for node {} sid:{} not yet ready",
234	                        res.expr(),
235	                        tree_sid.index(),
236	                        source
237	                    );
238	                }
239	            }
240	            None => tracing::error!(
241	                "Error propagating forget sub {}: cannot get index of {}!",
242	                res.expr(),
243	                source
244	            ),
245	        }
246	    }
247	
248	    pub(super) fn unregister_node_subscribers(
249	        &mut self,
250	        zid: &ZenohIdProto,
251	    ) -> HashSet<Arc<Resource>> {
252	        let removed_routers = self
253	            .net_mut()
254	            .remove_link(zid)
255	            .into_iter()
256	            .map(|(_, node)| node)
257	            .collect::<HashSet<_>>();
258	
259	        let mut resources = HashSet::new();
260	
261	        for mut res in self.router_subs.iter().cloned().collect_vec() {
262	            self.res_hat_mut(&mut res)
263	                .router_subs
264	                .retain(|router| !removed_routers.contains(router));
265	
266	            if self.res_hat(&res).router_subs.is_empty() {
267	                self.router_subs.retain(|r| !Arc::ptr_eq(r, &res));
268	                resources.insert(res);
269	            }
270	        }
271	
272	        resources
273	    }
274	}
