276	impl HatPubSubTrait for Hat {
277	    #[tracing::instrument(level = "debug", skip(tables), ret)]
278	    fn sourced_subscribers(&self, tables: &TablesData) -> HashMap<Arc<Resource>, Sources> {
279	        self.router_subs
280	            .iter()
281	            .map(|sub| {
282	                (
283	                    sub.clone(),
284	                    Sources {
285	                        routers: Vec::from_iter(
286	                            self.res_hat(sub)
287	                                .router_subs
288	                                .iter()
289	                                .copied()
290	                                .filter(|router| router != &tables.zid),
291	                        ),
292	                        peers: Vec::default(),
293	                        clients: Vec::default(),
294	                    },
295	                )
296	            })
297	            .collect()
298	    }
299	
300	    #[tracing::instrument(level = "debug", skip(_tables), ret)]
301	    fn sourced_publishers(&self, _tables: &TablesData) -> HashMap<Arc<Resource>, Sources> {
302	        HashMap::default()
303	    }
304	
305	    /// Computes routing destination for `Push` messages.
306	    ///
307	    /// # Dependencies
308	    ///
309	    /// ## Message properties
310	    /// + `src_region`
311	    /// + `res`
312	    /// + `node_id`
313	    ///
314	    /// ## This hat's state
315	    /// + `mres.router_subs` for all `mres` in `matches(res)`
316	    #[tracing::instrument(level = "debug", skip(tables, src_region), ret)]
317	    fn compute_data_route(
318	        &self,
319	        tables: &TablesData,
320	        src_region: &Region,
321	        expr: &RoutingExpr,
322	        node_id: NodeId,
323	    ) -> Arc<Route> {
324	        #[inline]
325	        fn insert_faces_for_subs(
326	            this: &Hat,
327	            route: &mut RouteBuilder<Direction>,
328	            expr: &RoutingExpr,
329	            tables: &TablesData,
330	            net: &Network,
331	            source: NodeId,
332	            subs: &HashSet<ZenohIdProto>,
333	        ) {
334	            if net.trees.len() > source as usize {
335	                for sub in subs {
336	                    if let Some(sub_idx) = net.get_idx(sub) {
337	                        if net.trees[source as usize].directions.len() > sub_idx.index() {
338	                            if let Some(direction) =
339	                                net.trees[source as usize].directions[sub_idx.index()]
340	                            {
341	                                if net.graph.contains_node(direction) {
342	                                    if let Some(face) = this.face(tables, &net.graph[direction].zid)
343	                                    {
344	                                        tracing::debug!(dst = %face, dst.has_subscriber = true);
345	                                        route.insert(face.id, || {
346	                                            let wire_expr = expr.get_best_key(face.id);
347	                                            Direction {
348	                                                dst_face: face.clone(),
349	                                                wire_expr: wire_expr.to_owned(),
350	                                                node_id: source,
351	                                            }
352	                                        });
353	                                    }
354	                                }
355	                            }
356	                        }
357	                    }
358	                }
359	            } else {
360	                tracing::trace!("Tree for node sid:{} not yet ready", source);
361	            }
362	        }
363	
364	        let mut route = RouteBuilder::<Direction>::new();
365	        let Some(key_expr) = expr.key_expr() else {
366	            return Arc::new(route.build());
367	        };
368	
369	        let matches = expr
370	            .resource()
371	            .as_ref()
372	            .and_then(|res| res.ctx.as_ref())
373	            .map(|ctx| Cow::from(&ctx.matches))
374	            .unwrap_or_else(|| Cow::from(Resource::get_matches(tables, key_expr)));
375	
376	        for mres in matches.iter() {
377	            let mres = mres.upgrade().unwrap();
378	
379	            let net = self.net();
380	            let router_source = if *src_region == self.region() {
381	                node_id
382	            } else {
383	                net.idx.index() as NodeId
384	            };
385	            insert_faces_for_subs(
386	                self,
387	                &mut route,
388	                expr,
389	                tables,
390	                net,
391	                router_source,
392	                &self.res_hat(&mres).router_subs,
393	            );
394	        }
395	
396	        Arc::new(route.build())
397	    }
398	
399	    #[tracing::instrument(level = "debug", skip(ctx, _id, node_id, info), ret)]
400	    fn register_subscriber(
401	        &mut self,
402	        ctx: DispatcherContext,
403	        _id: SubscriberId,
404	        mut res: Arc<Resource>,
405	        node_id: NodeId,
406	        info: &SubscriberInfo,
407	    ) {
408	        debug_assert!(self.owns(ctx.src_face));
409	
410	        let Some(router) = self.get_router(ctx.src_face, node_id) else {
411	            tracing::error!(%node_id, "Subscriber from unknown router");
412	            return;
413	        };
414	
415	        debug_assert_ne!(router, ctx.tables.zid);
416	
417	        self.res_hat_mut(&mut res).router_subs.insert(router);
418	        self.router_subs.insert(res.clone());
419	
420	        self.propagate_sourced_subscriber(ctx.tables, &res, info, Some(ctx.src_face), &router);
421	    }
422	
423	    #[tracing::instrument(level = "debug", skip(ctx, _id, node_id), ret)]
424	    fn unregister_subscriber(
425	        &mut self,
426	        ctx: DispatcherContext,
427	        _id: SubscriberId,
428	        res: Option<Arc<Resource>>,
429	        node_id: NodeId,
430	    ) -> Option<Arc<Resource>> {
431	        debug_assert!(self.owns(ctx.src_face));
432	
433	        let Some(router) = self.get_router(ctx.src_face, node_id) else {
434	            tracing::error!(%node_id, "Subscriber from unknown router");
435	            return None;
436	        };
437	
438	        debug_assert_ne!(router, ctx.tables.zid);
439	
440	        let Some(mut res) = res else {
441	            tracing::error!("Subscriber undeclaration in router region with no resource");
442	            return None;
443	        };
444	
445	        self.res_hat_mut(&mut res).router_subs.remove(&router);
446	        if self.res_hat(&res).router_subs.is_empty() {
447	            self.router_subs.retain(|r| !Arc::ptr_eq(r, &res));
448	        }
449	
450	        self.propagate_forget_sourced_subscriber(ctx.tables, &res, Some(ctx.src_face), &router);
451	
452	        Some(res)
453	    }
454	
455	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
456	    fn unregister_face_subscribers(&mut self, ctx: DispatcherContext) -> HashSet<Arc<Resource>> {
457	        self.unregister_node_subscribers(&ctx.src_face.zid)
458	    }
459	
460	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
461	    fn propagate_subscriber(
462	        &mut self,
463	        ctx: DispatcherContext,
464	        mut res: Arc<Resource>,
465	        other_info: Option<SubscriberInfo>,
466	    ) {
467	        let Some(other_info) = other_info else {
468	            // NOTE(regions): see Hat::register_subscriber
469	            debug_assert!(self.owns(ctx.src_face));
470	            return;
471	        };
472	
473	        if !self.res_hat(&res).router_subs.contains(&ctx.tables.zid) {
474	            self.res_hat_mut(&mut res)
475	                .router_subs
476	                .insert(ctx.tables.zid);
477	            self.router_subs.insert(res.clone());
478	
479	            self.propagate_sourced_subscriber(ctx.tables, &res, &other_info, None, &ctx.tables.zid);
480	        }
481	    }
482	
483	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
484	    fn unpropagate_subscriber(&mut self, ctx: DispatcherContext, mut res: Arc<Resource>) {
485	        if self.owns(ctx.src_face) {
486	            // NOTE(regions): see Hat::unregister_subscriber
487	            return;
488	        }
489	
490	        let was_propagated = self.res_hat(&res).router_subs.contains(&ctx.tables.zid);
491	
492	        debug_assert!(was_propagated);
493	
494	        if was_propagated {
495	            self.res_hat_mut(&mut res)
496	                .router_subs
497	                .remove(&ctx.tables.zid);
498	            if self.res_hat(&res).router_subs.is_empty() {
499	                self.router_subs.retain(|r| !Arc::ptr_eq(r, &res));
500	            }
501	
502	            self.propagate_forget_sourced_subscriber(ctx.tables, &res, None, &ctx.tables.zid);
503	        }
504	    }
505	
506	    #[tracing::instrument(level = "trace", ret)]
507	    fn remote_subscribers_of(&self, tables: &TablesData, res: &Resource) -> Option<SubscriberInfo> {
508	        self.res_hat(res)
509	            .router_subs
510	            .iter()
511	            .any(|router| router != &tables.zid)
512	            .then_some(SubscriberInfo)
513	    }
514	
515	    #[allow(clippy::incompatible_msrv)]
516	    #[tracing::instrument(level = "trace", skip(tables), ret)]
517	    fn remote_subscribers_matching(
518	        &self,
519	        tables: &TablesData,
520	        res: Option<&Resource>,
521	    ) -> HashMap<Arc<Resource>, SubscriberInfo> {
522	        self.router_subs
523	            .iter()
524	            .filter_map(|sub| {
525	                if self
526	                    .res_hat(sub)
527	                    .router_subs
528	                    .iter()
529	                    .any(|router| router != &tables.zid)
530	                    && res.is_none_or(|res| res.matches(sub))
531	                {
532	                    Some((sub.clone(), SubscriberInfo))
533	                } else {
534	                    None
535	                }
536	            })
537	            .collect()
538	    }
539	}
