32	use crate::net::routing::{
33	    dispatcher::{
34	        face::FaceState,
35	        pubsub::SubscriberInfo,
36	        region::RegionMap,
37	        resource::{FaceContext, NodeId, Resource},
38	        tables::{Route, RoutingExpr, TablesData},
39	    },
40	    gateway::{Direction, RouteBuilder, DEFAULT_NODE_ID},
41	    hat::{
42	        peer::{initial_interest, Hat, INITIAL_INTEREST_ID},
43	        DispatcherContext, HatBaseTrait, HatPubSubTrait, HatTrait, SendDeclare, Sources,
44	    },
45	    RoutingContext,
46	};
47	
48	impl Hat {
49	    #[tracing::instrument(level = "debug", skip_all, ret)]
50	    pub(super) fn repropagate_subscribers(
51	        &self,
52	        ctx: DispatcherContext,
53	        other_hats: &RegionMap<&dyn HatTrait>,
54	    ) {
55	        if ctx.src_face.region.bound().is_south() {
56	            tracing::debug!(face = %ctx.src_face, "New south-bound peer remote; not propagating subscribers");
57	            return;
58	        }
59	
60	        let info = SubscriberInfo;
61	
62	        for res in other_hats
63	            .values()
64	            .flat_map(|hat| hat.remote_subscribers(ctx.tables).into_keys())
65	        {
66	            // TODO(regions): we always propagate entities in this codepath; the method name is misleading
67	            self.maybe_propagate_subscriber(&res, &info, ctx.src_face, ctx.send_declare);
68	        }
69	    }
70	
71	    fn maybe_propagate_subscriber(
72	        &self,
73	        res: &Arc<Resource>,
74	        info: &SubscriberInfo,
75	        dst_face: &mut Arc<FaceState>,
76	        send_declare: &mut SendDeclare,
77	    ) {
78	        if self
79	            .face_hat(dst_face)
80	            .local_subs
81	            .contains_simple_resource(res)
82	        {
83	            return;
84	        };
85	
86	        // NOTE(regions): it's not because of initial interest that we push subscribers to north-bound peers.
87	        // Initial interest only exists to track current declarations at startup. This code is misleading.
88	        // See 20a95fb.
89	        let initial_interest = dst_face
90	            .region
91	            .bound()
92	            .is_north()
93	            .then_some(INITIAL_INTEREST_ID);
94	
95	        let (should_notify, simple_interests) = match initial_interest {
96	            Some(interest) => (true, HashSet::from([interest])),
97	            None => self
98	                .face_hat(dst_face)
99	                .remote_interests
100	                .iter()
101	                .filter(|(_, i)| i.options.subscribers() && i.matches(res))
102	                .fold(
103	                    (false, HashSet::new()),
104	                    |(_, mut simple_interests), (id, i)| {
105	                        if !i.options.aggregate() {
106	                            simple_interests.insert(*id);
107	                        }
108	                        (true, simple_interests)
109	                    },
110	                ),
111	        };
112	
113	        if !should_notify {
114	            return;
115	        }
116	
117	        let face_hat_mut = self.face_hat_mut(dst_face);
118	        let (_, subs_to_notify) = face_hat_mut.local_subs.insert_simple_resource(
119	            res.clone(),
120	            *info,
121	            || face_hat_mut.next_id.fetch_add(1, Ordering::SeqCst),
122	            simple_interests,
123	        );
124	
125	        for update in subs_to_notify {
126	            tracing::debug!(dst = %dst_face);
127	            let key_expr = Resource::decl_key(&update.resource, dst_face);
128	            send_declare(
129	                &dst_face.primitives,
130	                RoutingContext::with_expr(
131	                    Declare {
132	                        interest_id: None,
133	                        ext_qos: declare::ext::QoSType::DECLARE,
134	                        ext_tstamp: None,
135	                        ext_nodeid: declare::ext::NodeIdType::DEFAULT,
136	                        body: DeclareBody::DeclareSubscriber(DeclareSubscriber {
137	                            id: update.id,
138	                            wire_expr: key_expr.clone(),
139	                        }),
140	                    },
141	                    update.resource.expr().to_string(),
142	                ),
143	            );
144	        }
145	    }
146	
147	    fn maybe_unpropagate_subscriber(
148	        &self,
149	        face: &mut Arc<FaceState>,
150	        res: &Arc<Resource>,
151	        send_declare: &mut SendDeclare,
152	    ) {
153	        for update in self
154	            .face_hat_mut(face)
155	            .local_subs
156	            .remove_simple_resource(res)
157	        {
158	            tracing::debug!(dst = %face);
159	            send_declare(
160	                &face.primitives,
161	                RoutingContext::with_expr(
162	                    Declare {
163	                        interest_id: None,
164	                        ext_qos: declare::ext::QoSType::DECLARE,
165	                        ext_tstamp: None,
166	                        ext_nodeid: declare::ext::NodeIdType::DEFAULT,
167	                        body: DeclareBody::UndeclareSubscriber(UndeclareSubscriber {
168	                            id: update.id,
169	                            ext_wire_expr: WireExprType::null(),
170	                        }),
171	                    },
172	                    update.resource.expr().to_string(),
173	                ),
174	            );
175	        }
176	    }
177	}
178	
179	impl HatPubSubTrait for Hat {
180	    #[tracing::instrument(level = "debug", skip(tables), ret)]
181	    fn sourced_subscribers(&self, tables: &TablesData) -> HashMap<Arc<Resource>, Sources> {
182	        let mut subs = HashMap::new();
183	        for face in self.owned_faces(tables) {
184	            for sub in self.face_hat(face).remote_subs.values() {
185	                let srcs = subs.entry(sub.clone()).or_insert_with(Sources::empty);
186	                srcs.peers.push(face.zid);
187	            }
188	        }
189	        subs
190	    }
191	
192	    #[tracing::instrument(level = "debug", skip(tables), ret)]
193	    fn sourced_publishers(&self, tables: &TablesData) -> HashMap<Arc<Resource>, Sources> {
194	        let mut result = HashMap::new();
195	        for face in self.owned_faces(tables) {
196	            for res in self
197	                .face_hat(face)
198	                .remote_interests
199	                .values()
200	                .filter_map(|i| {
201	                    if i.options.subscribers() {
202	                        i.res.as_ref()
203	                    } else {
204	                        None
205	                    }
206	                })
207	            {
208	                result
209	                    .entry(res.clone())
210	                    .or_insert_with(Sources::default)
211	                    .peers
212	                    .push(face.zid);
213	            }
214	        }
215	        result.into_iter().collect()
216	    }
217	
218	    /// Computes routing destination for `Push` messages.
219	    ///
220	    /// # Dependencies
221	    ///
222	    /// ## Message properties
223	    /// + `src_region`
224	    /// + `expr`
225	    ///
226	    /// ## This hat's state
227	    /// + `owned_faces`
228	    /// + `mres.face_ctx.subs` for all `mres` in `matches(res)` and all owned faces in `mres`.
229	    /// + `mres.face_ctx.subscriber_interest_finalized` for all `mres` in `matches(res)` and all owned faces in `mres`.
230	    /// + `face.initial_interest_finalized` for all owned faces in `mres`.
231	    #[tracing::instrument(level = "debug", skip(tables, src_region, _node_id), ret)]
232	    fn compute_data_route(
233	        &self,
234	        tables: &TablesData,
235	        src_region: &Region,
236	        expr: &RoutingExpr,
237	        _node_id: NodeId,
238	    ) -> Arc<Route> {
239	        let mut route = RouteBuilder::<Direction>::new();
240	        let Some(key_expr) = expr.key_expr() else {
241	            return Arc::new(route.build());
242	        };
243	
244	        let matches = expr
245	            .resource()
246	            .as_ref()
247	            .and_then(|res| res.ctx.as_ref())
248	            .map(|ctx| Cow::from(&ctx.matches))
249	            .unwrap_or_else(|| Cow::from(Resource::get_matches(tables, key_expr)));
250	
251	        for mres in matches.iter() {
252	            let mres = mres.upgrade().unwrap();
253	
254	            for ctx in self.owned_face_contexts(&mres) {
255	                if ctx.subs.is_some() && self.region() != *src_region {
256	                    route.insert(ctx.face.id, || {
257	                        tracing::debug!(dst = %ctx.face, dst.has_subscriber = true);
258	                        let wire_expr = expr.get_best_key(ctx.face.id);
259	                        Direction {
260	                            dst_face: ctx.face.clone(),
261	                            wire_expr: wire_expr.to_owned(),
262	                            node_id: DEFAULT_NODE_ID,
263	                        }
264	                    });
265	                }
266	            }
267	        }
268	
269	        if self.region().bound().is_north() && src_region.bound().is_south() {
270	            for face in self
271	                .owned_faces(tables)
272	                .filter(|f| f.remote_bound.is_south())
273	            {
274	                route.try_insert(face.id, || {
275	                    let has_interest_finalized = expr
276	                        .resource()
277	                        .and_then(|res| res.face_ctxs.get(&face.id))
278	                        .is_some_and(|ctx| ctx.subscriber_interest_finalized);
279	                    (!has_interest_finalized).then(|| {
280	                        tracing::debug!(dst = %face, dst.has_unfinalized_subscriber_interest = true);
281	                        let wire_expr = expr.get_best_key(face.id);
282	                        Direction {
283	                            dst_face: face.clone(),
284	                            wire_expr: wire_expr.to_owned(),
285	                            node_id: DEFAULT_NODE_ID,
286	                        }
287	                    })
288	                });
289	            }
290	
291	            for face in self.owned_faces(tables).filter(|f| {
292	                f.remote_bound.is_north() && initial_interest(f).is_some_and(|i| !i.finalized)
293	            }) {
294	                tracing::debug!(dst = %face, dst.has_unfinalized_initial_interest = true);
295	                route.insert(face.id, || {
296	                    let wire_expr = expr.get_best_key(face.id);
297	                    Direction {
298	                        dst_face: face.clone(),
299	                        wire_expr: wire_expr.to_owned(),
300	                        node_id: DEFAULT_NODE_ID,
301	                    }
302	                });
303	            }
304	        }
305	
306	        // HACK(regions)
307	        for group in self.multicast_groups(tables) {
308	            route.insert(group.id, || {
309	                let wire_expr = expr.get_best_key(group.id);
310	                Direction {
311	                    dst_face: group.clone(),
312	                    wire_expr: wire_expr.to_owned(),
313	                    node_id: DEFAULT_NODE_ID,
314	                }
315	            });
316	        }
317	
318	        Arc::new(route.build())
319	    }
320	
321	    #[tracing::instrument(level = "debug", skip(ctx, id, _node_id, info), ret)]
322	    fn register_subscriber(
323	        &mut self,
324	        ctx: DispatcherContext,
325	        id: SubscriberId,
326	        mut res: Arc<Resource>,
327	        _node_id: NodeId,
328	        info: &SubscriberInfo,
329	    ) {
330	        debug_assert!(self.owns(ctx.src_face));
331	
332	        {
333	            let res = get_mut_unchecked(&mut res);
334	            match res.face_ctxs.get_mut(&ctx.src_face.id) {
335	                Some(ctx) => {
336	                    if ctx.subs.is_none() {
337	                        get_mut_unchecked(ctx).subs = Some(*info);
338	                    }
339	                }
340	                None => {
341	                    let ctx = res
342	                        .face_ctxs
343	                        .entry(ctx.src_face.id)
344	                        .or_insert_with(|| Arc::new(FaceContext::new(ctx.src_face.clone())));
345	                    get_mut_unchecked(ctx).subs = Some(*info);
346	                }
347	            }
348	        }
349	
350	        self.face_hat_mut(ctx.src_face)
351	            .remote_subs
352	            .insert(id, res.clone());
353	    }
354	
355	    #[tracing::instrument(level = "debug", skip(ctx, _res, _node_id), ret)]
356	    fn unregister_subscriber(
357	        &mut self,
358	        ctx: DispatcherContext,
359	        id: SubscriberId,
360	        _res: Option<Arc<Resource>>,
361	        _node_id: NodeId,
362	    ) -> Option<Arc<Resource>> {
363	        debug_assert!(self.owns(ctx.src_face));
364	
365	        let Some(mut res) = self.face_hat_mut(ctx.src_face).remote_subs.remove(&id) else {
366	            tracing::error!(id, "Unknown subscriber");
367	            return None;
368	        };
369	
370	        if self
371	            .face_hat(ctx.src_face)
372	            .remote_subs
373	            .values()
374	            .contains(&res)
375	        {
376	            tracing::debug!(id, ?res, "Duplicated subscriber");
377	            return None;
378	        };
379	
380	        if let Some(ctx) = get_mut_unchecked(&mut res)
381	            .face_ctxs
382	            .get_mut(&ctx.src_face.id)
383	        {
384	            get_mut_unchecked(ctx).subs = None;
385	        }
386	
387	        Some(res)
388	    }
389	
390	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
391	    fn unregister_face_subscribers(&mut self, ctx: DispatcherContext) -> HashSet<Arc<Resource>> {
392	        debug_assert!(self.owns(ctx.src_face));
393	
394	        let fid = ctx.src_face.id;
395	
396	        self.face_hat_mut(ctx.src_face)
397	            .remote_subs
398	            .drain()
399	            .map(|(_, mut res)| {
400	                if let Some(ctx) = get_mut_unchecked(&mut res).face_ctxs.get_mut(&fid) {
401	                    get_mut_unchecked(ctx).subs = None;
402	                }
403	
404	                res
405	            })
406	            .collect()
407	    }
408	
409	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
410	    fn propagate_subscriber(
411	        &mut self,
412	        ctx: DispatcherContext,
413	        res: Arc<Resource>,
414	        other_info: Option<SubscriberInfo>,
415	    ) {
416	        let Some(other_info) = other_info else {
417	            debug_assert!(self.owns(ctx.src_face));
418	            return;
419	        };
420	
421	        for dst_face in self.owned_faces_mut(ctx.tables) {
422	            self.maybe_propagate_subscriber(&res, &other_info, dst_face, ctx.send_declare);
423	        }
424	
425	        // TODO(regions): does this still cause a "buffer overflow" on Windows?
426	        #[cfg(not(windows))]
427	        {
428	            // HACK(regions): if we have a multicast group, we use it to propagate subscribers to upstream gateways.
429	            for group in self.multicast_groups(ctx.tables) {
430	                tracing::debug!(dst = %group);
431	                (ctx.send_declare)(
432	                    &group.primitives,
433	                    RoutingContext::with_expr(
434	                        Declare {
435	                            interest_id: None,
436	                            ext_qos: declare::ext::QoSType::DECLARE,
437	                            ext_tstamp: None,
438	                            ext_nodeid: declare::ext::NodeIdType::DEFAULT,
439	                            body: DeclareBody::DeclareSubscriber(DeclareSubscriber {
440	                                id: SubscriberId::default(),
441	                                wire_expr: res.expr().to_string().into(),
442	                            }),
443	                        },
444	                        res.expr().to_string(),
445	                    ),
446	                );
447	            }
448	        }
449	    }
450	
451	    #[tracing::instrument(level = "debug", skip(ctx), ret)]
452	    fn unpropagate_subscriber(&mut self, ctx: DispatcherContext, res: Arc<Resource>) {
453	        if self.owns(ctx.src_face) {
454	            return;
455	        }
456	
457	        for mut face in self.owned_faces(ctx.tables).cloned() {
458	            self.maybe_unpropagate_subscriber(&mut face, &res, ctx.send_declare);
459	        }
460	    }
461	
462	    #[tracing::instrument(level = "trace", ret)]
463	    fn remote_subscribers_of(
464	        &self,
465	        _tables: &TablesData,
466	        res: &Resource,
467	    ) -> Option<SubscriberInfo> {
468	        self.owned_face_contexts(res)
469	            .filter_map(|ctx| ctx.subs)
470	            .reduce(|_, _| SubscriberInfo)
471	    }
472	
473	    #[allow(clippy::incompatible_msrv)]
474	    #[tracing::instrument(level = "trace", skip(tables), ret)]
475	    fn remote_subscribers_matching(
476	        &self,
477	        tables: &TablesData,
478	        res: Option<&Resource>,
479	    ) -> HashMap<Arc<Resource>, SubscriberInfo> {
480	        self.owned_faces(tables)
481	            .flat_map(|f| self.face_hat(f).remote_subs.values())
482	            .filter(|&sub| res.is_none_or(|res| res.matches(sub)))
483	            .map(|sub| (sub.clone(), SubscriberInfo))
484	            .collect()
485	    }
486	}
